/**
 * Exercise Type Icon block — server-side render.
 *
 * Renders a Phosphor icon matching the post's nop_exercise_type term.
 * All icons are Phosphor Regular (fill weight, 256×256 viewBox) to match
 * the icon family used across the plugin. Outputs nothing on the front end
 * when the post has no exercise type — editor falls back to the run icon so
 * the block stays visible in the Site Editor canvas.
 */

declare( strict_types=1 );

// Prevent direct file access.
if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

$is_editor = defined( 'REST_REQUEST' ) && REST_REQUEST
	&& isset( $_GET['context'] ) && 'edit' === $_GET['context']; // phpcs:ignore WordPress.Security.NonceVerification

$post_id = $block->context['postId'] ?? get_the_ID();
if ( $is_editor && isset( $_GET['post_id'] ) ) { // phpcs:ignore WordPress.Security.NonceVerification
	$candidate = absint( $_GET['post_id'] ); // phpcs:ignore WordPress.Security.NonceVerification
	if ( $candidate && current_user_can( 'edit_post', $candidate ) ) {
		$post_id = $candidate;
	}
}

$type = '';
if ( $post_id ) {
	$terms = wp_get_object_terms( $post_id, \NOP\IndieWeb\Kind\Exercise_Type_Taxonomy::TAXONOMY, [ 'fields' => 'slugs' ] );
	if ( ! is_wp_error( $terms ) && $terms ) {
		$type = (string) $terms[0];
	}
	if ( ! $type ) {
		$type = sanitize_key( (string) get_post_meta( $post_id, 'nop_indieweb_exercise_type', true ) );
	}
}

